// kernel/kernel_cpu.c
#include <stdio.h>
#include <stdlib.h>
#include <omp.h>

#define fp double

#define NUMBER_PAR_PER_BOX 100
#define NUMBER_THREADS 128
#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

typedef struct {
    fp x, y, z;
} THREE_VECTOR;

typedef struct {
    fp v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str {
    int x, y, z;
    int number;
    long offset;
} nei_str;

typedef struct box_str {
    int x, y, z;
    int number;
    long offset;
    int nn;
    nei_str nei[26];
} box_str;

typedef struct par_str {
    fp alpha;
} par_str;

typedef struct dim_str {
    int cur_arg;
    int arch_arg;
    int cores_arg;
    int boxes1d_arg;
    long number_boxes;
    long box_mem;
    long space_elem;
    long space_mem;
    long space_mem2;
} dim_str;

void kernel_cpu(par_str par, dim_str dim, box_str* box, FOUR_VECTOR* rv, fp* qv, FOUR_VECTOR* fv) {
    int bx, tx, wtx, k, j;
    fp a2, r2, u2, vij, fs, fxij, fyij, fzij;
    THREE_VECTOR d;
    FOUR_VECTOR* rA, *rB, *fA;
    fp* qB;
    int first_i, first_j, pointer;
    long long time0, time1, time2, time3, time4, time5, time6, time7;

    time0 = omp_get_wtime();

    #pragma omp parallel for private(bx, tx, wtx, k, j, a2, r2, u2, vij, fs, fxij, fyij, fzij, d, rA, rB, fA, qB, first_i, first_j, pointer)
    for (bx = 0; bx < dim.number_boxes; bx++) {
        tx = 0;
        wtx = 0;

        if (dim.number_boxes > bx) {
            first_i = box[bx].offset;
            rA = &rv[first_i];
            fA = &fv[first_i];

            for (k = 0; k <= box[bx].nn; k++) {
                if (k == 0) {
                    pointer = bx;
                } else {
                    pointer = box[bx].nei[k - 1].number;
                }

                first_j = box[pointer].offset;
                rB = &rv[first_j];
                qB = &qv[first_j];

                #pragma omp parallel for private(j, r2, u2, vij, fs, fxij, fyij, fzij, d)
                for (j = 0; j < NUMBER_PAR_PER_BOX; j++) {
                    r2 = rv[first_i + tx].v + rv[first_j + j].v - DOT(rv[first_i + tx], rv[first_j + j]);
                    u2 = 2 * par.alpha * par.alpha * r2;
                    vij = exp(-u2);
                    fs = 2 * vij;

                    d.x = rv[first_i + tx].x - rv[first_j + j].x;
                    fxij = fs * d.x;
                    d.y = rv[first_i + tx].y - rv[first_j + j].y;
                    fyij = fs * d.y;
                    d.z = rv[first_i + tx].z - rv[first_j + j].z;
                    fzij = fs * d.z;

                    fv[first_i + tx].v += qv[first_j + j] * vij;
                    fv[first_i + tx].x += qv[first_j + j] * fxij;
                    fv[first_i + tx].y += qv[first_j + j] * fyij;
                    fv[first_i + tx].z += qv[first_j + j] * fzij;
                }
            }
        }
    }

    time1 = omp_get_wtime();

    printf("Time spent in different stages of the application:\n");
    printf("%15.12f s, %15.12f % : KERNEL: COMPUTE\n", (float) (time1-time0) / 1000000, (float) (time1-time0) / (float) (time1-time0) * 100);
    printf("Total time:\n");
    printf("%.12f s\n", (float) (time1-time0) / 1000000);
}
